namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple and delicious pizza with fresh mozzarella, tomatoes, and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = ["Preheat oven to 475°F.", "Roll out dough on a floured surface.", "Spread crushed tomatoes evenly.", "Tear mozzarella and distribute on top.", "Bake for 10–12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
                TotalRatings = 12, RatingSum = 50
            },
            new Recipe
            {
                Id = 2, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken pieces in a creamy, spiced tomato sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato puree", "Heavy cream", "Onion", "Garlic", "Ginger"],
                Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or pan-fry chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato puree and simmer.", "Stir in cream and garam masala.", "Add chicken and simmer 10 minutes."],
                TotalRatings = 8, RatingSum = 35
            },
            new Recipe
            {
                Id = 3, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy pasta with pancetta, egg, and Parmesan.",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Parmesan cheese", "Black pepper", "Salt"],
                Steps = ["Cook spaghetti in salted boiling water.", "Fry pancetta until crispy.", "Whisk eggs with grated Parmesan and pepper.", "Drain pasta, reserving some water.", "Toss hot pasta with pancetta, then egg mixture.", "Serve immediately with extra Parmesan."],
                TotalRatings = 15, RatingSum = 68
            },
            new Recipe
            {
                Id = 4, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh avocado dip with lime and cilantro.",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Salt", "Tomato"],
                Steps = ["Halve and pit avocados; scoop into a bowl.", "Mash to desired consistency.", "Stir in diced onion, jalapeño, tomato, and cilantro.", "Add lime juice and salt to taste.", "Serve immediately with tortilla chips."],
                TotalRatings = 6, RatingSum = 27
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef in warm tortillas with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream"],
                Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water; simmer 5 minutes.", "Warm tortillas in a dry pan.", "Fill tortillas with beef.", "Top with lettuce, tomato, cheese, and sour cream."],
                TotalRatings = 10, RatingSum = 42
            },
            new Recipe
            {
                Id = 6, Title = "Pad Thai", Category = "Thai",
                Description = "Stir-fried rice noodles with shrimp, peanuts, and tangy sauce.",
                Ingredients = ["Rice noodles", "Shrimp", "Eggs", "Bean sprouts", "Green onions", "Peanuts", "Tamarind paste", "Fish sauce", "Lime"],
                Steps = ["Soak rice noodles in warm water 20 minutes; drain.", "Stir-fry shrimp until pink; set aside.", "Scramble eggs in the same pan.", "Add noodles, tamarind paste, and fish sauce; toss.", "Return shrimp; add bean sprouts and green onions.", "Serve topped with crushed peanuts and lime wedges."],
                TotalRatings = 9, RatingSum = 40
            },
        ];
        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public void AddRecipe(RecipeSubmission submission)
    {
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = submission.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        });
    }
}

@page "/category/{CategoryName}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (_recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="recipe-list">
        @foreach (var recipe in _recipes)
        {
            <div class="recipe-card">
                <h3><a href="/recipe/@recipe.Id">@recipe.Title</a></h3>
                <p>@recipe.Description</p>
                <span class="rating-badge">
                    ⭐ @recipe.AverageRating.ToString("0.0") (@recipe.TotalRatings ratings)
                </span>
            </div>
        }
    </div>
}

<p><a href="/">← Back to categories</a></p>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    private List<Recipe> _recipes = [];

    protected override void OnInitialized()
    {
        _recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

@if (_recipe is null)
{
    <PageTitle>Not Found — RecipeShare</PageTitle>
    <h1>Recipe not found</h1>
    <p><a href="/">← Back to home</a></p>
}
else
{
    <PageTitle>@_recipe.Title — RecipeShare</PageTitle>

    <h1>@_recipe.Title</h1>
    <span class="category-tag">@_recipe.Category</span>

    <p class="recipe-description">@_recipe.Description</p>

    <h2>Ingredients</h2>
    <ul>
        @foreach (var ingredient in _recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h2>Steps</h2>
    <ol>
        @foreach (var step in _recipe.Steps)
        {
            <li>@step</li>
        }
    </ol>

    <h2>Rate This Recipe</h2>
    <StarRating RecipeId="_recipe.Id" CurrentAverage="_recipe.AverageRating" TotalRatings="_recipe.TotalRatings" />

    <p style="margin-top: 2rem;"><a href="/category/@_recipe.Category">← Back to @_recipe.Category recipes</a></p>
}

@code {
    [Parameter] public int Id { get; set; }
    private Recipe? _recipe;

    protected override void OnInitialized()
    {
        _recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _hoveredStar ? "hovered" : "") @(star <= _selectedStar ? "selected" : "")"
              @onmouseover="() => _hoveredStar = star"
              @onmouseout="() => _hoveredStar = 0"
              @onclick="() => SubmitRating(star)">
            ★
        </span>
    }

    @if (_submitted)
    {
        <span class="rating-thanks">Thanks for rating!</span>
    }

    <span class="rating-info">
        ⭐ @_average.ToString("0.0") (@_totalRatings ratings)
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int TotalRatings { get; set; }

    private int _hoveredStar;
    private int _selectedStar;
    private bool _submitted;
    private double _average;
    private int _totalRatings;

    protected override void OnInitialized()
    {
        _average = CurrentAverage;
        _totalRatings = TotalRatings;
    }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        _selectedStar = stars;
        _submitted = true;

        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            _average = recipe.AverageRating;
            _totalRatings = recipe.TotalRatings;
        }
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>

@if (_submitted)
{
    <div class="alert-success">
        <strong>Recipe submitted!</strong> Your recipe has been added.
        <a href="/">Browse recipes</a>
    </div>
}
else
{
    <EditForm Model="_submission" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />

        <div class="form-group">
            <label for="title">Recipe Title</label>
            <InputText id="title" @bind-Value="_submission.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="form-group">
            <label for="category">Category</label>
            <InputSelect id="category" @bind-Value="_submission.Category" class="form-control">
                <option value="">— Select a category —</option>
                @foreach (var cat in _categories)
                {
                    <option value="@cat">@cat</option>
                }
                <option value="Other">Other</option>
            </InputSelect>
        </div>

        <div class="form-group">
            <label for="ingredients">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="_submission.Ingredients" class="form-control" rows="6"
                           placeholder="2 cups flour&#10;1 cup sugar&#10;3 apples, sliced" />
        </div>

        <div class="form-group">
            <label for="steps">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="_submission.Steps" class="form-control" rows="6"
                           placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients." />
        </div>

        <button type="submit" class="btn-submit">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeSubmission _submission = new();
    private List<string> _categories = [];
    private bool _submitted;

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(_submission.Title) ||
            string.IsNullOrWhiteSpace(_submission.Category) ||
            string.IsNullOrWhiteSpace(_submission.Ingredients) ||
            string.IsNullOrWhiteSpace(_submission.Steps))
            return;

        RecipeService.AddRecipe(_submission);
        _submitted = true;
    }
}

